const results = [];
for (const _inputItem of $input.all()) {
const item = _inputItem.json;
const bodyRaw = item.body_text || '';
const subjRaw = item.subject || '';
const fromEmailRaw = (item.from_email || '').toLowerCase();
const body = bodyRaw.toLowerCase();
const subj = subjRaw.toLowerCase();
const combined = subj + ' ' + body;

const bounceSignals = ['mailer-daemon', 'postmaster@', 'noreply', 'no-reply', 'undeliverable', 'delivery status notification', 'address not found', 'user unknown', 'mailbox full'];
let isBounce = false;
for (const s of bounceSignals) {
  if (fromEmailRaw.includes(s) || subj.includes(s) || body.includes(s)) { isBounce = true; break; }
}

const unsubSignals = ['unsubscribe', 'remove me', 'take me off', 'stop emailing', 'do not contact', 'leave me alone', 'opt out', 'opt-out', 'no more emails'];
let isUnsub = false;
for (const s of unsubSignals) { if (combined.includes(s)) { isUnsub = true; break; } }

// Report-complaint detection: customer paid, received report, is unhappy with quality.
// Distinct from generic negative because this is actionable (auto-regenerate) not routing to churn.
const reportComplaintSignals = [
  'report is wrong', 'report is confusing', 'report is not', 'not what i paid for',
  'not what I asked for', 'missed my point', 'missed the point', 'doesn\'t address',
  'does not address', 'doesnt address', 'regenerate', 'redo the report',
  'redo my report', 'report is off', 'report was off', 'report seems',
  'not accurate', 'inaccurate report', 'wrong about my business',
  'refund my', 'refund the report', 'wasted my money', 'this is useless',
];
let isReportComplaint = false;
for (const s of reportComplaintSignals) { if (combined.includes(s)) { isReportComplaint = true; break; } }

const pos = ['interested','tell me more','sounds good','want to learn','let s talk','schedule','book','yes','definitely','love to','great','when can','how much','price','cost','demo','free website'];
const neg = ['no thanks','not interested','not right now','spam','not now','not a fit','wrong person','pass','no thank you'];

let pc = 0, nc = 0;
for (const s of pos) { if (combined.includes(s)) pc++; }
for (const s of neg) { if (combined.includes(s)) nc++; }

let intent;
if (isBounce) intent = 'bounce';
else if (isUnsub) intent = 'unsubscribe';
else if (isReportComplaint) intent = 'report_complaint';
else if (nc > 0) intent = 'negative';
else if (pc >= 1) intent = 'positive';
else intent = 'neutral';

results.push({json: {...item, intent, pos_signals: pc, neg_signals: nc, is_bounce: isBounce, is_unsub: isUnsub, is_report_complaint: isReportComplaint}});
}
return results;

